#include<iostream>
using namespace std;
int main()
{
    unsigned short a=67;
    signed short b=-235;
    int c=45;
    long d=65535;
    long long e=03036277335;
    //size of variables
    cout<<"size of u_short="<<sizeof(a)<<endl;
    cout<<"size of s_short"<<sizeof(b)<<endl;
    cout<<"size of c"<<sizeof(c)<<endl;
    cout<<"size of long d="<<sizeof(d)<<endl;
    cout<<"size of long long e="<<sizeof(e)<<endl;
    //values of variables
    cout<<"a="<<a<<endl;
    cout<<"a="<<a<<endl;
    cout<<"b="<<b<<endl;
    cout<<"c="<<c<<endl;
    cout<<"d="<<d<<endl;
    cout<<"e="<<e<<endl;
}



